🎀 **Python Decorators** are functions that modify the behavior of another function — they're syntactic sugar for higher-order functions.

```python
import functools
import time

def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f'{func.__name__} took {end-start:.4f}s')
        return result
    return wrapper

@timer
def slow_function():
    time.sleep(1)
    return 'done'
```

Common decorators: `@property`, `@staticmethod`, `@classmethod`, `@functools.lru_cache`

🌳 **Binary Trees** — hierarchical data with at most 2 children per node:

```python
class TreeNode:
    def __init__(self, val):
        self.val = val
        self.left = self.right = None

# Tree traversals
def inorder(root):   # Left → Root → Right (BST: sorted output)
    if root:
        inorder(root.left)
        print(root.val)
        inorder(root.right)

def preorder(root):  # Root → Left → Right (copy tree)
    if root:
        print(root.val)
        preorder(root.left)
        preorder(root.right)

def levelorder(root):  # BFS
    from collections import deque
    q = deque([root])
    while q:
        node = q.popleft()
        print(node.val)
        if node.left: q.append(node.left)
        if node.right: q.append(node.right)
```

**BST property:** left < root < right

⚡ **Dynamic Programming** — break problems into overlapping subproblems:

**Two approaches:**
1. **Memoization** (top-down): cache recursive results
2. **Tabulation** (bottom-up): fill table iteratively

```python
# Fibonacci — Memoization
from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n):
    if n <= 1: return n
    return fib(n-1) + fib(n-2)

# Fibonacci — Tabulation O(n) time, O(1) space
def fib_dp(n):
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

# Longest Common Subsequence
def lcs(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]
```

🧪 **Testing in Python with pytest:**

```python
# calculator.py
def add(a: float, b: float) -> float:
    return a + b

def divide(a: float, b: float) -> float:
    if b == 0:
        raise ValueError('Cannot divide by zero')
    return a / b

# test_calculator.py
import pytest
from calculator import add, divide

class TestAdd:
    def test_positive_numbers(self):
        assert add(2, 3) == 5

    def test_negative_numbers(self):
        assert add(-1, -1) == -2

    @pytest.mark.parametrize('a,b,expected', [
        (1, 2, 3), (0, 0, 0), (-1, 1, 0)
    ])
    def test_parametrized(self, a, b, expected):
        assert add(a, b) == expected

def test_divide_by_zero():
    with pytest.raises(ValueError, match='divide by zero'):
        divide(5, 0)
```

